 * @LastEditors: Weidows
 * @LastEditTime: 2023-06-08 11:50:41
 * @FilePath: \Blog-private\source\_posts\experience\shell\奇技淫巧.md
 * @Description:
 * @!: *********************************************************************
--&gt;
&lt;blockquote class=&#34;pullquote mindmap mindmap-md&#34;&gt;&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;#%E6%88%8F%E8%80%8D%E8%84%9A%E6%9C%AC%E4%B8%AD%E5%A5%87%E6%8A%80%E6%B7%AB%E5%B7%A7&#34;&gt;戏耍脚本中~奇技淫巧&lt;/a&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;#%E5%8F%82%E6%95%B0%E5%88%A4%E7%A9%BA&#34;&gt;参数判空&lt;/a&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;#%E5%AD%97%E7%AC%A6%E4%B8%B2%E6%8B%BC%E6%8E%A5%E5%88%A4%E5%AE%9A&#34;&gt;字符串拼接判定&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E8%AF%AD%E6%B3%95%E5%88%A4%E5%AE%9A&#34;&gt;语法判定&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E7%A8%8B%E5%BA%8F%E5%8D%A0%E7%94%A8-%E5%90%8E%E5%8F%B0%E5%90%AF%E5%8A%A8&#34;&gt;程序占用-后台启动&lt;/a&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;#aria2&#34;&gt;aria2&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E5%A5%97%E5%A8%83&#34;&gt;套娃&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#echo&#34;&gt;echo&lt;/a&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;#%E5%85%B6%E4%B8%80&#34;&gt;其一&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E5%85%B6%E4%BA%8C&#34;&gt;其二&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#scoop&#34;&gt;Scoop&lt;/a&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;#portable&#34;&gt;portable&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E8%A7%A3%E5%89%96-exe&#34;&gt;解剖-exe&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E5%88%A4%E6%96%AD%E6%98%AF%E5%90%A6%E5%90%AB%E6%9C%89%E6%9F%90%E5%AD%97%E7%AC%A6%E4%B8%B2&#34;&gt;判断是否含有某字符串&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E5%85%B3%E4%BA%8E%E7%9B%AE%E5%BD%95&#34;&gt;关于目录&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#xml-error&#34;&gt;XML-error&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E5%88%A0%E9%99%A4%E6%89%80%E6%9C%89%E6%96%87%E4%BB%B6%E4%B8%8B%E4%B8%8B%E6%9F%90%E6%96%87%E4%BB%B6&#34;&gt;删除所有文件下下某文件&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#latex2word&#34;&gt;latex2word&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E5%80%9F%E7%89%A9%E8%A1%A8&#34;&gt;借物表&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;分割线&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;参数判空&#34;&gt;参数判空&lt;/h2&gt;
&lt;h3 id=&#34;字符串拼接判定&#34;&gt;字符串拼接判定&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;有时候我们想判断一个变量是不是空的,会变得有些棘手&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;if [ $&amp;#123;abc&amp;#125; != &amp;quot;&amp;quot; ]; then&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  echo $&amp;#123;abc&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;fi&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;我们的想法是判断是否存在 abc 这个变量,实际上这样写并不行,没有这个变量的话会变成下面的样子:&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;if [  != &amp;quot;&amp;quot; ]; then&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  echo $&amp;#123;abc&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;fi&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;这样肯定会报错的&lt;/p&gt;
&lt;hr&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;改一下,比如添加冗余校验字符&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;abc = &amp;quot;abc&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;if [ a$&amp;#123;abc&amp;#125; != a ]; then&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  echo $&amp;#123;abc&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;fi&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;hr&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;bat 中引号也会视为变量一部分&lt;/code&gt;,所以:&lt;/p&gt;
&lt;figure class=&#34;highlight bat&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; &amp;quot;&lt;span class=&#34;variable&#34;&gt;%DIRNAME%&lt;/span&gt;&amp;quot; == &amp;quot;&amp;quot; &lt;span class=&#34;built_in&#34;&gt;set&lt;/span&gt; DIRNAME=.&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;或者:&lt;/p&gt;
&lt;figure class=&#34;highlight bat&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;set&lt;/span&gt; abc=&amp;quot;&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;%abc%&lt;/span&gt; == &amp;quot;&amp;quot; (&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;built_in&#34;&gt;echo&lt;/span&gt; &amp;quot;abc为空&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;跟 shell 语法差别很大来着, 注意别写错…&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;语法判定&#34;&gt;语法判定&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;shell 的语法:&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;if [ -n &amp;quot;$&amp;#123;abc&amp;#125;&amp;quot; ]; then&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  echo $&amp;#123;abc&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;fi&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;bat 语法:&lt;/p&gt;
&lt;figure class=&#34;highlight bat&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;not&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;defined&lt;/span&gt; abc (&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;built_in&#34;&gt;echo&lt;/span&gt; &amp;#x27;abc&amp;#x27; &lt;span class=&#34;keyword&#34;&gt;not&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;defined&lt;/span&gt;.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;程序占用-后台启动&#34;&gt;程序占用-后台启动&lt;/h2&gt;
&lt;h3 id=&#34;aria2&#34;&gt;aria2&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;如果你用过 aria2 的话肯定会遇到一个头疼的事: &lt;code&gt;如何开机后台自动启动它&lt;/code&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;它的程序本身不带有开机启动,需要另外写启动脚本&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;它无法后台启动,必然会占据一个控制台程序的前台&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;网上找到了比较好用的方法: &lt;code&gt;vbs 脚本&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;由于我平时用 bat 管理电脑,单独编写执行一个 vbs 脚本略显多余,所以直接结合进 bat 脚本里,用完就删针刺激:&lt;/p&gt;
&lt;figure class=&#34;highlight bat&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;echo&lt;/span&gt; CreateObject(&amp;quot;WScript.Shell&amp;quot;).Run &amp;quot;aria2c --conf-&lt;span class=&#34;built_in&#34;&gt;path&lt;/span&gt;=D:\Game\Scoop\persist\aria2\conf&amp;quot;,&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt; &amp;gt; aria2.vbs&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cscript //Nologo aria2.vbs&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;del&lt;/span&gt; aria2.vbs&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;后来又发现一个更好的: &lt;code&gt;用 powershell 后台启动&lt;/code&gt; &lt;sup id=&#39;cite_ref-3&#39;&gt;&lt;a href=&#34;#cite_note-3&#34;&gt;[3]&lt;/a&gt;&lt;/sup&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight cmd&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;powershell &lt;span class=&#34;built_in&#34;&gt;Start&lt;/span&gt;-Process -WindowStyle hidden aria2c.exe --conf-&lt;span class=&#34;built_in&#34;&gt;path&lt;/span&gt;=D:\Repos\Weidows-projects\Keeper\Programming-Configuration\others\aria2\aria2.conf&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;套娃&#34;&gt;套娃&lt;/h3&gt;
&lt;p&gt;如上, sharemouse 也存在这问题, 通过套娃解决了:&lt;/p&gt;
&lt;figure class=&#34;highlight nix&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;start &lt;span class=&#34;symbol&#34;&gt;/b&lt;/span&gt; cmd &lt;span class=&#34;symbol&#34;&gt;/c&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;C:&lt;span class=&#34;char escape_&#34;&gt;\P&lt;/span&gt;rogram Files (x86)&lt;span class=&#34;char escape_&#34;&gt;\S&lt;/span&gt;hareMouse&lt;span class=&#34;char escape_&#34;&gt;\S&lt;/span&gt;hareMouse.exe&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;分割线&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;echo&#34;&gt;echo&lt;/h2&gt;
&lt;h3 id=&#34;其一&#34;&gt;其一&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;看到一个脚本中这么写,乍一看蒙了:&lt;/p&gt;
&lt;figure class=&#34;highlight bat&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;CLS&lt;/span&gt;&amp;amp;&lt;span class=&#34;built_in&#34;&gt;ECHO&lt;/span&gt;.&amp;amp;&lt;span class=&#34;built_in&#34;&gt;ECHO&lt;/span&gt; 完成, 以下选项自选：&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;ECHO&lt;/span&gt;.&amp;amp;&lt;span class=&#34;built_in&#34;&gt;ECHO&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;、启用视频播放程序(会驻留进程)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;实际上只是把几个命令压缩到了一行&lt;/p&gt;
&lt;figure class=&#34;highlight avrasm&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;cls&lt;/span&gt;   &lt;span class=&#34;meta&#34;&gt;# 清屏&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;echo. &lt;span class=&#34;meta&#34;&gt;# 换行&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;其二&#34;&gt;其二&lt;/h3&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;hello world&amp;quot;&lt;/span&gt; | xargs &lt;span class=&#34;built_in&#34;&gt;echo&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;脱裤子放一个颇有技巧的新活屁&lt;/p&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;分割线&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;Scoop&#34;&gt;Scoop&lt;/h2&gt;
&lt;h3 id=&#34;portable&#34;&gt;portable&lt;/h3&gt;
&lt;p&gt;我们可以通过创建虚拟链接把 C 盘中的 runtime 数据 -&amp;gt; scoop/persist 内&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;此片段可自动判断 &lt;code&gt;remix-ide / .remix-ipfsnode / .cache_remix_ide&lt;/code&gt; 所在目录是 &lt;code&gt;USERPROFILE / APPDATA&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;并将数据移动到 persist 内,创建虚拟链接&lt;/p&gt;
&lt;p&gt;&lt;code&gt;需要注意只能是文件夹,不能是文件!!!&lt;/code&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight nsis&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;foreach (&lt;span class=&#34;variable&#34;&gt;$folder&lt;/span&gt; in @(&amp;#x27;remix-ide&amp;#x27;, &amp;#x27;.remix-ipfsnode&amp;#x27;, &amp;#x27;.cache_remix_ide&amp;#x27;)) &amp;#123;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;  if (Test-Path \&amp;quot;&lt;/span&gt;&lt;span class=&#34;variable&#34;&gt;$env&lt;/span&gt;:USERPROFILE\\&lt;span class=&#34;variable&#34;&gt;$folder&lt;/span&gt;\&lt;span class=&#34;string&#34;&gt;&amp;quot;) &amp;#123;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;    &lt;span class=&#34;variable&#34;&gt;$runtimeCache&lt;/span&gt; = \&amp;quot;&lt;/span&gt;&lt;span class=&#34;variable&#34;&gt;$env&lt;/span&gt;:USERPROFILE\\&lt;span class=&#34;variable&#34;&gt;$folder&lt;/span&gt;\&lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;    &lt;span class=&#34;variable&#34;&gt;$runtimeCachePersist&lt;/span&gt; = \&amp;quot;&lt;/span&gt;&lt;span class=&#34;variable&#34;&gt;$persist_dir&lt;/span&gt;\\USERPROFILE\\&lt;span class=&#34;variable&#34;&gt;$folder&lt;/span&gt;\&lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;  &amp;#125; else &amp;#123;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;    if (Test-Path \&amp;quot;&lt;/span&gt;&lt;span class=&#34;variable&#34;&gt;$env&lt;/span&gt;:APPDATA\\&lt;span class=&#34;variable&#34;&gt;$folder&lt;/span&gt;\&lt;span class=&#34;string&#34;&gt;&amp;quot;) &amp;#123;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;      &lt;span class=&#34;variable&#34;&gt;$runtimeCache&lt;/span&gt; = \&amp;quot;&lt;/span&gt;&lt;span class=&#34;variable&#34;&gt;$env&lt;/span&gt;:APPDATA\\&lt;span class=&#34;variable&#34;&gt;$folder&lt;/span&gt;\&lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;      &lt;span class=&#34;variable&#34;&gt;$runtimeCachePersist&lt;/span&gt; = \&amp;quot;&lt;/span&gt;&lt;span class=&#34;variable&#34;&gt;$persist_dir&lt;/span&gt;\\APPDATA\\&lt;span class=&#34;variable&#34;&gt;$folder&lt;/span&gt;\&lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;    &amp;#125; else &amp;#123;continue&amp;#125;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;  &amp;#125;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;  if (Test-Path &lt;span class=&#34;variable&#34;&gt;$runtimeCachePersist&lt;/span&gt;) &amp;#123;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;    Remove-Item &lt;span class=&#34;variable&#34;&gt;$runtimeCache&lt;/span&gt; -Force -Recurse -ErrorAction SilentlyContinue&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;    New-Item -Type Junction -Path &lt;span class=&#34;variable&#34;&gt;$runtimeCache&lt;/span&gt; -Target &lt;span class=&#34;variable&#34;&gt;$runtimeCachePersist&lt;/span&gt; | Out-Null&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;  &amp;#125; else &amp;#123;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;    mkdir &lt;span class=&#34;variable&#34;&gt;$runtimeCache&lt;/span&gt;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;    Move-Item &lt;span class=&#34;variable&#34;&gt;$runtimeCache&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;$runtimeCachePersist&lt;/span&gt; -Force&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;    New-Item -Type Junction -Path &lt;span class=&#34;variable&#34;&gt;$runtimeCache&lt;/span&gt; -Target &lt;span class=&#34;variable&#34;&gt;$runtimeCachePersist&lt;/span&gt; | Out-Null&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;  &amp;#125;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;#125;&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;以及配对的 uninstaller:&lt;/p&gt;
&lt;figure class=&#34;highlight nsis&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;uninstaller&amp;quot;&lt;/span&gt;: &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;string&#34;&gt;&amp;quot;script&amp;quot;&lt;/span&gt;: [&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;string&#34;&gt;&amp;quot;foreach (&lt;span class=&#34;variable&#34;&gt;$folder&lt;/span&gt; in @(&amp;#x27;remix-ide&amp;#x27;, &amp;#x27;.remix-ipfsnode&amp;#x27;, &amp;#x27;.cache_remix_ide&amp;#x27;)) &amp;#123;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;string&#34;&gt;&amp;quot;  if (Test-Path \&amp;quot;&lt;/span&gt;&lt;span class=&#34;variable&#34;&gt;$env&lt;/span&gt;:USERPROFILE\\&lt;span class=&#34;variable&#34;&gt;$folder&lt;/span&gt;\&lt;span class=&#34;string&#34;&gt;&amp;quot;) &amp;#123;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;string&#34;&gt;&amp;quot;    &lt;span class=&#34;variable&#34;&gt;$runtimeCache&lt;/span&gt; = \&amp;quot;&lt;/span&gt;&lt;span class=&#34;variable&#34;&gt;$env&lt;/span&gt;:USERPROFILE\\&lt;span class=&#34;variable&#34;&gt;$folder&lt;/span&gt;\&lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;string&#34;&gt;&amp;quot;    &lt;span class=&#34;variable&#34;&gt;$runtimeCachePersist&lt;/span&gt; = \&amp;quot;&lt;/span&gt;&lt;span class=&#34;variable&#34;&gt;$persist_dir&lt;/span&gt;\\USERPROFILE\\&lt;span class=&#34;variable&#34;&gt;$folder&lt;/span&gt;\&lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;string&#34;&gt;&amp;quot;  &amp;#125; else &amp;#123;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;string&#34;&gt;&amp;quot;    if (Test-Path \&amp;quot;&lt;/span&gt;&lt;span class=&#34;variable&#34;&gt;$env&lt;/span&gt;:APPDATA\\&lt;span class=&#34;variable&#34;&gt;$folder&lt;/span&gt;\&lt;span class=&#34;string&#34;&gt;&amp;quot;) &amp;#123;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;string&#34;&gt;&amp;quot;      &lt;span class=&#34;variable&#34;&gt;$runtimeCache&lt;/span&gt; = \&amp;quot;&lt;/span&gt;&lt;span class=&#34;variable&#34;&gt;$env&lt;/span&gt;:APPDATA\\&lt;span class=&#34;variable&#34;&gt;$folder&lt;/span&gt;\&lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;string&#34;&gt;&amp;quot;      &lt;span class=&#34;variable&#34;&gt;$runtimeCachePersist&lt;/span&gt; = \&amp;quot;&lt;/span&gt;&lt;span class=&#34;variable&#34;&gt;$persist_dir&lt;/span&gt;\\APPDATA\\&lt;span class=&#34;variable&#34;&gt;$folder&lt;/span&gt;\&lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;string&#34;&gt;&amp;quot;    &amp;#125; else &amp;#123;continue&amp;#125;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;string&#34;&gt;&amp;quot;  &amp;#125;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;string&#34;&gt;&amp;quot;  if (!(Test-Path &lt;span class=&#34;variable&#34;&gt;$runtimeCachePersist&lt;/span&gt;)) &amp;#123; Move-Item &lt;span class=&#34;variable&#34;&gt;$runtimeCache&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;$runtimeCachePersist&lt;/span&gt; -Force -ErrorAction SilentlyContinue &amp;#125;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;string&#34;&gt;&amp;quot;  else &amp;#123; Remove-Item &lt;span class=&#34;variable&#34;&gt;$runtimeCache&lt;/span&gt; -Force -Recurse -ErrorAction SilentlyContinue &amp;#125;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;#125;&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    ]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;解剖-exe&#34;&gt;解剖-exe&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;此片段可以把常见的 &lt;code&gt;.exe -&amp;gt; .exe#/dl.7z&lt;/code&gt; 中的文件提取出来&lt;/p&gt;
&lt;figure class=&#34;highlight lsl&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;Expand-7zipArchive &lt;span class=&#34;subst&#34;&gt;\&amp;quot;&lt;/span&gt;$dir&lt;span class=&#34;subst&#34;&gt;\\&lt;/span&gt;`$PLUGINSDIR&lt;span class=&#34;subst&#34;&gt;\\&lt;/span&gt;app-64.7z&lt;span class=&#34;subst&#34;&gt;\&amp;quot;&lt;/span&gt; &lt;span class=&#34;subst&#34;&gt;\&amp;quot;&lt;/span&gt;$dir&lt;span class=&#34;subst&#34;&gt;\&amp;quot;&lt;/span&gt;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;Remove-Item -Recurse -Force &lt;span class=&#34;subst&#34;&gt;\&amp;quot;&lt;/span&gt;$dir&lt;span class=&#34;subst&#34;&gt;\\&lt;/span&gt;`$PLUGINSDIR&lt;span class=&#34;subst&#34;&gt;\&amp;quot;&lt;/span&gt;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;分割线&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;判断是否含有某字符串&#34;&gt;判断是否含有某字符串&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;如下,可以判断.gitignore 中是否含有 ‘backup’&lt;/p&gt;
&lt;figure class=&#34;highlight bat&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;cat &lt;span class=&#34;variable&#34;&gt;%BACKUP_DIR%&lt;/span&gt;\.gitignore | &lt;span class=&#34;built_in&#34;&gt;findstr&lt;/span&gt; backup &amp;gt;&lt;span class=&#34;built_in&#34;&gt;nul&lt;/span&gt; || (&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;built_in&#34;&gt;echo&lt;/span&gt; backup&amp;gt;&amp;gt; &lt;span class=&#34;variable&#34;&gt;%BACKUP_DIR%&lt;/span&gt;\.gitignore&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;分割线&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;关于目录&#34;&gt;关于目录&lt;/h2&gt;
&lt;figure class=&#34;highlight bat&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;@&lt;span class=&#34;built_in&#34;&gt;echo&lt;/span&gt; off&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pwd&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;echo&lt;/span&gt; %&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;echo&lt;/span&gt; %~dp0&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight console&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;╰─ cmd /c &amp;quot;d:\Repos\Weidows-projects\Keeper\test.bat&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;/d/Repos/Weidows-projects/Keeper&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;d:\Repos\Weidows-projects\Keeper\test.bat&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;d:\Repos\Weidows-projects\Keeper\&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;分割线&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;XML-error&#34;&gt;XML-error&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;error on line 228 at column 35: Input is not proper UTF-8, indicate encoding !&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;这个报错它的意思是有字符并不是 UTF-8 编码, 虽然它报错指明的文件位置是对的, 但是 line/column 有可能不对&lt;/p&gt;
&lt;p&gt;比如 jupyter-lab 运行的输出有时候会带有 XML 不支持的特殊符号 &lt;sup id=&#39;cite_ref-1&#39;&gt;&lt;a href=&#34;#cite_note-1&#34;&gt;[1]&lt;/a&gt;&lt;/sup&gt; (即使 echo $LANG 是 UTF-8)&lt;/p&gt;
&lt;p&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/blog/Zlkb8Q.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;解决办法就是通过 UTF-8 编码打开, 把这种符号全删掉保存 (&lt;a href=&#34;https://github.com/Weidows-projects/public-post/blob/main/notebook/convert.sh#L45&#34;&gt;参见脚本&lt;/a&gt;)&lt;/p&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;分割线&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;删除所有文件下下某文件&#34;&gt;删除所有文件下下某文件&lt;/h2&gt;
&lt;figure class=&#34;highlight awk&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;regexp&#34;&gt;/mnt/&lt;/span&gt;test_data&lt;span class=&#34;regexp&#34;&gt;/Movie/&lt;/span&gt;&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;/a.txt&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;regexp&#34;&gt;/mnt/&lt;/span&gt;test_data&lt;span class=&#34;regexp&#34;&gt;/Movie/&lt;/span&gt;&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;/a.txt&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;regexp&#34;&gt;/mnt/&lt;/span&gt;test_data&lt;span class=&#34;regexp&#34;&gt;/Movie/&lt;/span&gt;&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;/a.txt&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;regexp&#34;&gt;/mnt/&lt;/span&gt;test_data&lt;span class=&#34;regexp&#34;&gt;/Movie/&lt;/span&gt;&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;/a.txt&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;如上, 想批量删除 1,2,3,4 文件夹下的 a.txt 文件 &lt;sup id=&#39;cite_ref-2&#39;&gt;&lt;a href=&#34;#cite_note-2&#34;&gt;[2]&lt;/a&gt;&lt;/sup&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight gradle&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;find&lt;/span&gt; &lt;span class=&#34;regexp&#34;&gt;/mnt/&lt;/span&gt;test_data&lt;span class=&#34;regexp&#34;&gt;/Movie/&lt;/span&gt; -maxdepth &lt;span class=&#34;number&#34;&gt;3&lt;/span&gt; -name output_face | xargs rm -rf&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;分割线&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;latex2word&#34;&gt;latex2word&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;pandoc -s &lt;a href=&#34;http://1.md&#34;&gt;1.md&lt;/a&gt; -o 1.docx&lt;/li&gt;
&lt;li&gt;typora 导出&lt;/li&gt;
&lt;li&gt;obsidian 搜索并安装 pandoc 插件, 导出&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;分割线&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;借物表&#34;&gt;借物表&lt;/h2&gt;
&lt;p&gt;&lt;a name=&#39;cite_note-1&#39; href=&#39;#cite_ref-1&#39;&gt;[1]&lt;/a&gt;: &lt;a href=&#34;https://blog.huati365.com/c4a41e416d7e30a8&#34;&gt;Input is not proper UTF-8, indicate encoding !错误处理&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;&lt;a name=&#39;cite_note-2&#39; href=&#39;#cite_ref-2&#39;&gt;[2]&lt;/a&gt;: &lt;a href=&#34;https://www.ruanyifeng.com/blog/2019/08/xargs-tutorial.html&#34;&gt;xargs 命令教程 - 阮一峰的网络日志&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;&lt;a name=&#39;cite_note-3&#39; href=&#39;#cite_ref-3&#39;&gt;[3]&lt;/a&gt;: &lt;a href=&#34;https://blog.csdn.net/qq_27979907/article/details/114280470&#34;&gt;windows 通过 cmd 后台运行进程方法&lt;em&gt;cmd 后端运行&lt;/em&gt;吉吉教主的博客-CSDN 博客&lt;/a&gt;&lt;/p&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.css&#34;&gt;

 &lt;h1&gt;极致专攻-Shell-Optimize&lt;/h1&gt;
&lt;!--
 * @Author: Weidows
 * @LastEditors: Weidows
 * @LastEditTime: 2023-04-20 18:26:49
 * @FilePath: \Blog-private\source\_posts\experience\shell\optimize.md
--&gt;
&lt;blockquote class=&#34;pullquote mindmap mindmap-md&#34;&gt;&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;#%E6%9E%81%E8%87%B4%E4%B8%93%E6%94%BB-shell-optimize&#34;&gt;极致专攻-Shell-Optimize&lt;/a&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;#pwsh&#34;&gt;pwsh&lt;/a&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;#%E9%A2%84%E8%A7%88&#34;&gt;预览&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E5%AE%89%E8%A3%85&#34;&gt;安装&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E6%8F%92%E4%BB%B6-%E9%85%8D%E7%BD%AE&#34;&gt;插件-配置&lt;/a&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;#oh-my-posh&#34;&gt;oh-my-posh&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#poshfuck&#34;&gt;PoshFuck&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#posh-git&#34;&gt;posh-git&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#psreadline&#34;&gt;PSReadline&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E5%90%AF%E7%94%A8%E7%AE%A1%E7%90%86%E5%91%98%E6%A8%A1%E5%BC%8F&#34;&gt;启用管理员模式&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E6%8A%A5%E9%94%99&#34;&gt;报错&lt;/a&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;#%E5%8F%82%E6%95%B0%E6%95%B0%E9%87%8F%E9%97%AE%E9%A2%98&#34;&gt;参数数量问题&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#zsh&#34;&gt;zsh&lt;/a&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;#%E5%AE%89%E8%A3%85-1&#34;&gt;安装&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E4%B8%BB%E9%A2%98&#34;&gt;主题&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E5%80%9F%E7%89%A9%E8%A1%A8&#34;&gt;借物表&lt;/a&gt;&lt;/li&gt;
